var insertionSortList = function(head) {
    const dummy = new ListNode(0);
    let cur = head;
    while (cur) {
        const nxt = cur.next;
        let prev = dummy;
        while (prev.next && prev.next.val <= cur.val) {
            prev = prev.next;
        }
        cur.next = prev.next;
        prev.next = cur;
        cur = nxt;
    }
    return dummy.next;
};
